package cliutil

import (
	"context"
	"database/sql"
	"fmt"
	"time"
)

// Decision is the outcome of a freshness check. It tells the caller what
// action the freshness hook took or why it was skipped.
type Decision string

const (
	DecisionFresh      Decision = "fresh"
	DecisionStaleAPI   Decision = "stale-api"
	DecisionStaleShare Decision = "stale-share"
	// DecisionNoStore means the caller asked about freshness but the store
	// was not found or not initialized.
	DecisionNoStore Decision = "no-store"
	DecisionSkipped Decision = "skipped"
	DecisionError   Decision = "error"
)

func (d Decision) String() string { return string(d) }

// Policy configures a freshness check. StaleAfter is the default threshold
// for considering cached data stale. EnvOptOut is an environment variable
// that, when set to "1", disables auto-refresh.
type Policy struct {
	StaleAfter time.Duration
	EnvOptOut  string
}

// EnsureFresh checks whether the given resources are fresh according to
// the policy. It returns the decision and an error if the check itself fails.
func EnsureFresh(_ context.Context, db *sql.DB, resources []string, policy Policy) (Decision, error) {
	if db == nil {
		return DecisionNoStore, nil
	}
	staleAfter := policy.StaleAfter
	if staleAfter == 0 {
		staleAfter = 24 * time.Hour
	}
	for _, resource := range resources {
		var updatedAt time.Time
		row := db.QueryRow("SELECT value FROM _sync_meta WHERE key = ?", resource)
		var ts string
		if err := row.Scan(&ts); err != nil {
			return DecisionNoStore, nil
		}
		t, err := time.Parse(time.RFC3339, ts)
		if err != nil {
			return DecisionNoStore, nil
		}
		updatedAt = t
		if time.Since(updatedAt) > staleAfter {
			return DecisionStaleAPI, nil
		}
	}
	return DecisionFresh, nil
}

// DataProvenance records where data for a command response came from.
// Source is "live" when data was fetched directly from the API, "cache"
// when it was read from the local SQLite store, or "mock" during tests.
type DataProvenance struct {
	Source   string    // "live", "cache", or "mock"
	CachedAt time.Time // non-zero when Source is "cache"
}

// FreshnessMeta is the stable agent-facing metadata shape for commands that
// participate in machine-owned freshness. Generated JSON provenance envelopes
// attach this under meta.freshness.
type FreshnessMeta struct {
	Decision  string   `json:"decision"`             // fresh, stale-api, stale-share, no-store, skipped, or error
	Ran       bool     `json:"ran"`                  // true when the hook attempted a refresh
	Reason    string   `json:"reason,omitempty"`     // fresh, refreshed, refresh_failed, data_source_live, etc.
	Resources []string `json:"resources,omitempty"`  // resource keys checked
	Source    string   `json:"source,omitempty"`     // data source mode (auto, live, local)
	Error     string   `json:"error,omitempty"`      // error message if decision is "error"
	ElapsedMS int64    `json:"elapsed_ms,omitempty"` // wall-clock spent in the freshness hook
}

// NewFreshnessMeta builds a FreshnessMeta from a DataProvenance value.
// For live-source data, Decision is "fresh" with Reason "data_source_live".
// For cache-source data, Decision and Reason reflect the cache age.
func NewFreshnessMeta(p DataProvenance) *FreshnessMeta {
	switch p.Source {
	case "live":
		return &FreshnessMeta{Decision: "fresh", Ran: false, Reason: "data_source_live", Source: "live"}
	case "mock":
		return &FreshnessMeta{Decision: "skipped", Ran: false, Reason: "mock", Source: "mock"}
	default:
		if p.CachedAt.IsZero() {
			return &FreshnessMeta{Decision: "no-store", Ran: false, Source: "cache"}
		}
		age := time.Since(p.CachedAt)
		if age <= 30*time.Minute {
			return &FreshnessMeta{Decision: "fresh", Ran: false, Reason: fmt.Sprintf("cached %s ago", formatFreshnessAge(age)), Source: "cache"}
		}
		return &FreshnessMeta{Decision: "stale-api", Ran: false, Reason: fmt.Sprintf("cached %s ago", formatFreshnessAge(age)), Source: "cache"}
	}
}

// IsFresh reports whether the provenance represents live or very recently
// cached data (within maxAge). Callers use this to decide whether to
// surface a staleness warning alongside the response.
func IsFresh(p DataProvenance, maxAge time.Duration) bool {
	if p.Source == "live" || p.Source == "mock" {
		return true
	}
	if p.CachedAt.IsZero() {
		return false
	}
	return time.Since(p.CachedAt) <= maxAge
}

func formatFreshnessAge(d time.Duration) string {
	if d < time.Minute {
		return "just now"
	}
	if d < time.Hour {
		return fmt.Sprintf("%dm", int(d.Minutes()))
	}
	if d < 24*time.Hour {
		return fmt.Sprintf("%.1fh", d.Hours())
	}
	return fmt.Sprintf("%.1fd", d.Hours()/24)
}
